#include <bits/stdc++.h>
using namespace std;
const int maxn=5e4+5;
int n,siz[maxn],mx[maxn],sum,dep[maxn],cnt;
vector<int> ans(2,maxn);
vector<int> g[maxn];
void dfs(int u,int fa) {
	siz[u]=1;
	mx[u]=0;
	for(auto v:g[u]){
		if(v==fa){
			continue;
		}
		dfs(v,u);
		siz[u]+=siz[v];
		mx[u]=max(mx[u],siz[v]);
	}
	mx[u]=max(mx[u],n-siz[u]);
	if(mx[u]<=n/2){
		ans[cnt++]=u;
	}
}
void dfs1(int u,int fa){
	sum+=dep[u];
	for(auto e:g[u]){
		if(e!=fa){
			dep[e]=dep[u]+1;
			dfs1(e,u);
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<n; i++) {
		int a,b;
		cin>>a>>b;

		g[a].emplace_back(b);
		g[b].emplace_back(a);
	}
	dfs(1,0);
	cout<<min(ans[1],ans[0])<<" ";
	dfs1(min(ans[1],ans[0]),0);
	cout<<sum;
	return 0;
}
